#include <bits/stdc++.h>using namespace std;typedef long long ll; int main(){    int n;    cin >> n;    const int MAXN = 200001;    vector<bool> is_prime(MAXN + 1, true);    is_prime[0] = is_prime[1] = false;    for (ll i = 2; i * i <= MAXN; i++){        if (is_prime[i]){            for (ll j = i * i; j <= MAXN; j += i){                is_prime[j] = false;            }        }    }    vector<ll> sieve;    for (int i = 2; i <= MAXN; i++){        if (is_prime[i])sieve.push_back(i);    }    vector<ll> a(n, 0);    ll mx = 0;    for (int i = 0; i < n; i++)    {        cin >> a[i];        mx = max(mx, a[i]);    }    map<ll, vector<ll>> factors;    for (int i = 0; i < n; i++){        ll x = a[i];        for (ll p : sieve){            if (p * p > x) break;            if (x % p == 0){                ll cnt = 0;                while (x % p == 0){                    x /= p;                    cnt++;                }                factors[p].push_back(cnt);            }        }        if (x > 1)factors[x].push_back(1);    }    ll ans = 1;    for (auto &[p, vec] : factors){        if (vec.size() < n - 1) continue;        while (vec.size() < n)vec.push_back(0);        sort(vec.begin(), vec.end());        ll power = vec[1];        for (int i = 0; i < power; i++)ans *= p;    }    cout << ans << " ";}